(function (global) {  'use strict';   var modalEl =null;  var videoEl =null;  var titleEl =null;  var errorEl =null;  var snapBtn =null;  var modal =null;  var stream =null;  var activeSlot =-1;  var captureDone =null;   function stopStream() {    if (!stream) return;    stream.getTracks().forEach(function (track) {      try {track.stop();} catch (e) {}    });    stream =null;    if (videoEl) videoEl.srcObject =null; }    function showError(text) {    if (!errorEl) return;    if (!text) {      errorEl.textContent ='';      errorEl.classList.add('d-none');      return;   }     errorEl.textContent =text;    errorEl.classList.remove('d-none'); }    function closeModal() {    stopStream();    showError('');    if (modal) modal.hide(); }    function finish(file) {    var done =captureDone;    captureDone =null;    activeSlot =-1;    closeModal();    if (typeof done ==='function') done(file||null); }    function snapPhoto() {    if (!videoEl||!videoEl.videoWidth||!videoEl.videoHeight) {      showError('Камера ещё не готова. Подождите секунду и попробуйте снова.');      return;   }     var canvas =document.createElement('canvas');    canvas.width =videoEl.videoWidth;    canvas.height =videoEl.videoHeight;    var ctx =canvas.getContext('2d');    if (!ctx) {      finish(null);      return;   }     ctx.drawImage(videoEl,0,0,canvas.width,canvas.height);    canvas.toBlob(function (blob) {      if (!blob) {        finish(null);        return;     }       var name ='listing-slot-'+(activeSlot+1)+'-'+Date.now()+'.jpg';      finish(new File([blob],name,{type:'image/jpeg'}));   },'image/jpeg',0.92); }    function openCamera(slotIdx,slotLabel,done) {    captureDone =done;    activeSlot =slotIdx;    showError('');    if (titleEl) {      titleEl.textContent =slotLabel?('Снять фото: '+slotLabel):'Снять фото';   }     if (!global.navigator||!global.navigator.mediaDevices||!global.navigator.mediaDevices.getUserMedia) {      finish(null);      return;   }     if (!modalEl||!videoEl||!global.bootstrap) {      finish(null);      return;   }     if (!modal) {      modal =new global.bootstrap.Modal(modalEl,{backdrop:'static',keyboard:true});      modalEl.addEventListener('hidden.bs.modal',function () {        if (captureDone) finish(null);     });   }     global.navigator.mediaDevices.getUserMedia({      video:{facingMode:{ideal:'environment'}},      audio:false    }).then(function (mediaStream) {      stream =mediaStream;      videoEl.srcObject =mediaStream;      modal.show();   }).catch(function () {      showError('Не удалось открыть камеру. Разрешите доступ к камере в браузере.');      finish(null);   }); }    function capture(slotIdx,slotLabelOrDone,maybeDone) {    var label ='';    var done =maybeDone;    if (typeof slotLabelOrDone ==='function') {      done =slotLabelOrDone;   } else {      label =slotLabelOrDone||'';   }     openCamera(slotIdx,label,done); }    function init() {    modalEl =document.getElementById('iaPhotoCameraModal');    videoEl =document.getElementById('iaPhotoCameraVideo');    titleEl =document.getElementById('iaPhotoCameraTitle');    errorEl =document.getElementById('iaPhotoCameraError');    snapBtn =document.getElementById('iaPhotoCameraSnap');    if (!modalEl||!videoEl||!snapBtn) return;    snapBtn.addEventListener('click',snapPhoto); }    if (document.readyState ==='loading') {    document.addEventListener('DOMContentLoaded',init); } else {    init(); }    global.iaListingPhotoCamera ={capture:capture};})(window);
